-- ATAD2 Seed Data - Generated from source JSON
-- Run this on the Supabase postgres instance

-- Step 1: Create atad2_context_questions if missing
CREATE TABLE IF NOT EXISTS public.atad2_context_questions (
  id uuid NOT NULL DEFAULT gen_random_uuid(),
  question_id text NOT NULL,
  answer_trigger text NOT NULL CHECK (answer_trigger = ANY (ARRAY['Yes'::text, 'No'::text])),
  context_question text NOT NULL,
  created_at timestamptz DEFAULT now(),
  CONSTRAINT atad2_context_questions_pkey PRIMARY KEY (id)
);
ALTER TABLE public.atad2_context_questions ENABLE ROW LEVEL SECURITY;

-- Step 2: Create/replace match_documents function
DROP FUNCTION IF EXISTS match_documents(vector, integer, jsonb);
CREATE OR REPLACE FUNCTION match_documents (
  query_embedding vector(1536),
  match_count int DEFAULT 5,
  filter jsonb DEFAULT '{}'
) RETURNS TABLE (
  id bigint,
  content text,
  metadata jsonb,
  similarity float
)
LANGUAGE plpgsql
AS $$
BEGIN
  RETURN QUERY
  SELECT
    documents.id,
    documents.content,
    documents.metadata,
    1 - (documents.embedding <=> query_embedding) AS similarity
  FROM documents
  WHERE documents.metadata @> filter
  ORDER BY documents.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;

-- Step 3: Seed atad2_questions (100 rows)
TRUNCATE TABLE public.atad2_questions;
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('027cda02-7518-4cf2-9d40-cd4b765401d3', '3', 'Is the Dutch domestic taxpayer part of an international structure?', 'No', '28', '0.00', '', '', '2025-08-03 16:49:21.766755+00', '2025-12-27 19:20:00.763516+00', 'International structure', false, 'This question determines whether the taxpayer forms part of a cross-border or international structure, which is relevant because most hybrid mismatches within the scope of the Dutch anti-hybrid rules (ATAD2) arise in a cross-border context.

Answer “yes” if the Dutch domestic taxpayer is part of an international structure. This includes, in particular, situations where the taxpayer:

has one or more foreign parent companies, subsidiaries or sister companies, or

is otherwise part of a group with activities, entities or permanent establishments outside the Netherlands.

The presence of any cross-border element within the group or structure is sufficient to answer this question with “yes”.

Answer “no” if the taxpayer operates exclusively within the Netherlands and is not part of any group or structure with foreign entities, foreign permanent establishments or other cross-border elements.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('05b0d130-3168-4039-b44f-7814ee586fda', '21b', 'Is this deemed payment disregarded for tax purposes in the country where the permanent establishment is located?', 'Unknown', '22b', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-28 21:10:25.941585+00', 'Disregarded deemed payment at PE level', false, 'This question determines whether a deemed or notional payment between the head office and the permanent establishment is ignored (disregarded) for tax purposes in the country where the permanent establishment is located.

A deemed payment is regarded as disregarded if, under the tax law or treaty practice of the permanent establishment state, internal dealings between a head office and its permanent establishment are not recognised as taxable transactions. This is typically the case where the permanent establishment state:

- does not recognise internal interest, royalties or service charges between a head office and its permanent establishment,

- determines the taxable profit of the permanent establishment solely on the basis of an overall profit allocation, without recognising internal transactions, or

- treats the head office and the permanent establishment as a single taxpayer for purposes of profit taxation.

Answer “yes” if the deemed payment is ignored for tax purposes in the permanent establishment state and therefore does not give rise to taxable income at the level of the permanent establishment.

Answer “no” if the permanent establishment state does recognise such deemed payments and includes them in the determination of the taxable profit of the permanent establishment.

This assessment must be made from the perspective of the permanent establishment state');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('06c001cc-e339-4f37-b0c3-c8183ba202ec', '2', 'Is the taxpayer a legal entity that is not a resident of the Netherlands, but is subject to Dutch corporate income tax as a non-resident taxpayer because it has a permanent establishment in the Netherlands?', 'Yes', '31', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-27 19:15:04.490891+00', 'Non-resident taxpayer', true, 'This question determines whether the taxpayer falls within the scope of Dutch corporate income tax as a non-resident taxpayer and therefore whether the Dutch anti-hybrid rules (ATAD2) may apply.

Answer “yes” if the taxpayer qualifies as a Dutch non-resident corporate income taxpayer under Article 3 of the Dutch Corporate Income Tax Act. This includes, in particular:

entities that are not tax resident in the Netherlands, but that derive Dutch-source income through a permanent establishment in the Netherlands within the meaning of Dutch tax law or an applicable tax treaty, and are therefore subject to Dutch corporate income tax with respect to the profits attributable to that permanent establishment.

Answer “no” if the taxpayer does not have a permanent establishment in the Netherlands and is therefore not treated as a Dutch non-resident corporate income taxpayer under Dutch tax law.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('0bd7a984-048a-4823-8479-8f892a1f0626', '34', 'Is the deemed payment (see previous question) included in the taxable base of the other party, being the foreign head office or one of its permanent establishments?', 'No', '35', '1.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-08-03 16:49:21.766755+00', '2025-12-28 20:20:37.839078+00', 'Inclusion of deemed payment by foreign head office or PE', true, 'Answer “yes” if the deemed payment is included in a taxable base for a profit tax in the jurisdiction of the foreign head office or the relevant permanent establishment, regardless of the applicable tax rate or the availability of loss relief.

Answer “no” if the deemed payment is not included in a profit tax base at the level of the other party, for example because internal dealings are disregarded, the permanent establishment is not recognised, or the allocation is not followed for tax purposes.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('0cf90206-7c84-4f07-8b11-9e472b0a384e', '23b', 'Is the received amount (partially) allocated to a foreign permanent establishment of the Dutch domestic taxpayer, and therefore not fully included in the Dutch tax base?', 'Unknown', '26', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-28 12:34:46.715049+00', 'Allocation of inbound payment to foreign PE', false, 'This question determines whether the income received by the Dutch domestic taxpayer is wholly or partly attributed to a foreign permanent establishment, as a result of which that income is not fully included in the Dutch tax base.

Answer “yes” if, under Dutch tax law and applicable tax treaties, the received amount is (partly) allocated to a foreign permanent establishment of the taxpayer and therefore falls outside the Dutch taxable profit, for example because the foreign permanent establishment’s profits are exempt under the object exemption.

Answer “no” if the received amount is fully included in the Dutch tax base and no part of the income is attributed to a foreign permanent establishment.

This question is relevant because allocating income to a foreign permanent establishment may result in the income not being taxed in the Netherlands, which requires further assessment under the Dutch anti-hybrid rules to determine whether the income is taxed in the state of the permanent establishment or gives rise to a hybrid mismatch.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('0d067eef-a692-4a6d-900c-dd6787a21bb1', '27', 'Does the hybrid entity receive a payment or remuneration from an associated enterprise that is in principle deductible at the level of that associated enterprise, while that payment is not included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as tax transparent?', 'No', '28', '0.00', 'Hybrid entity', 'An entity that is regarded as a taxable entity under the laws of one State, and whose income or expenditure is treated as income or expenditure of one or more other entities or individuals under the laws of another jurisdiction.', '2025-12-29 20:51:14.295455+00', '2025-12-29 20:51:14.295455+00', 'Deductible payment to hybrid entity', false, 'This question determines whether the payment received by the hybrid entity is not included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as tax transparent, which may give rise to a hybrid mismatch from the perspective of the Dutch participant.

Answer "yes" if, because the hybrid entity is treated as tax transparent in the relevant jurisdiction, the payment is not recognised as taxable income at the level of the hybrid entity or its participant(s). In that case, the payment is deducted by the payer but not taxed anywhere, which may constitute a deduction without inclusion within the scope of the Dutch anti-hybrid rules.

Answer "no" if the payment is included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as transparent, for example because the income is taxed at the level of one or more participants.

A "yes" answer indicates a potential ATAD2 risk and requires further assessment to determine whether the Dutch secondary rule applies and whether the income must be included in the Dutch tax base.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('0ff1167f-2537-41da-9a1a-8adcabc0d0a4', '35', 'Does a non-EU permanent establishment of the non-resident taxpayer make a deemed payment to the Dutch permanent establishment, which is deductible from the profit in the non-EU country where the payment is considered to take place?', 'No', 'end', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-08-04 18:53:04.196731+00', 'Deemed payment from non-EU PE to Dutch PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('109d8a07-6e49-47e1-b87b-8ca50c71436a', '1', 'Is the taxpayer subject to Dutch corporate income tax as a Dutch domestic taxpayer?
', 'No', '2', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-28 21:06:21.695835+00', 'Resident taxpayer', false, 'This question determines whether the taxpayer falls within the scope of Dutch corporate income tax and therefore whether the Dutch anti-hybrid rules (ATAD 2) may apply.

Answer “yes” if the taxpayer qualifies as a Dutch domestic corporate income taxpayer under Article 2 of the Dutch Corporate Income Tax Act. This includes, in particular:

- entities that are tax resident in the Netherlands, meaning that their place of effective management is located in the Netherlands, based on the facts and circumstances, or

- entities that are incorporated under Dutch law and subject to Dutch corporate income tax, such as a private limited company (BV), public limited company (NV), or cooperative, or

- transparent partnerships or similar entities that qualify as an inverse hybrid entity and are therefore treated as a Dutch corporate income taxpayer under specific anti-hybrid provisions.

Answer “no” if the taxpayer does not fall within any of these categories and is not treated as a Dutch corporate income taxpayer under Dutch tax law.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('10db5bf1-c0bc-4cf0-b891-d6519bf06d64', '31', 'Is the foreign head office of the Dutch permanent establishment located outside the EU?', 'Unknown', '33', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:51.209418+00', 'Non-EU head office', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('155a495b-53ba-4e26-b8cf-b2e9696a0d84', '35', 'Does a non-EU permanent establishment of the non-resident taxpayer make a deemed payment to the Dutch permanent establishment, which is deductible from the profit in the non-EU country where the payment is considered to take place?', 'Unknown', 'end', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:55.770279+00', NULL, false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('19b02846-a8ca-4295-b702-17d2c7aa53ff', '35', 'Does a non-EU permanent establishment of the non-resident taxpayer make a deemed payment to the Dutch permanent establishment, which is deductible from the profit in the non-EU country where the payment is considered to take place?', 'Yes', 'end', '1.00', 'Example 6', 'A Dutch PE includes an asset on its balance sheet. Another PE in a different country, makes a deemed payment to the Dutch PE for the use of this asset. Under Dutch tax law, this usage, and therefore the deemed payment, is not recognised. If the country of the foreign PE allows deduction of the deemed payment, the Dutch PE must include the revenue as part of its profit (to prevent a deduction without inclusion).', '2025-08-03 16:49:21.766755+00', '2025-08-26 17:30:49.962771+00', 'Deemed payment from non-EU PE to Dutch PE', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('2779758f-b5c1-4b04-91b7-3701b3709235', '15', 'Does the Dutch domestic taxpayer have one or more foreign permanent establishments?', 'Unknown', '26', '0.10', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-11 17:48:52.737035+00', '2025-12-28 10:46:41.524829+00', 'Foreign PE of taxpayer', false, 'This question determines whether the Dutch domestic taxpayer has a foreign permanent establishment for Dutch tax purposes.

Answer “yes” if, based on Dutch tax law and an applicable tax treaty, the taxpayer carries on business abroad through a permanent establishment. The assessment must be made from a Dutch tax perspective, meaning that it is not decisive how the foreign jurisdiction itself qualifies the activities or presence.

Answer “no” if, when assessed under Dutch tax law and relevant tax treaties, no foreign permanent establishment exists, even if the foreign jurisdiction takes a different view.

This question is relevant because differences in the recognition or allocation of income to a permanent establishment may give rise to hybrid mismatches within the scope of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('296efc9d-e7a1-481b-be78-9171c2aa918e', '19', 'Is the same remuneration, payment, expense or loss deducted both by the Dutch domestic taxpayer (head office) and by one or more of its foreign permanent establishments?', 'Yes', '20b', '1.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-28 21:09:24.636896+00', 'Double deduction HO+PE', true, 'This question determines whether a double deduction may arise in relation to foreign permanent establishments.

A double deduction exists where the same remuneration, payment, expense or loss is taken into account more than once for the purposes of a tax on profits. In the context of permanent establishments, this may occur where costs are:

- deducted by the Dutch domestic taxpayer at head office level, and

- also deducted by one or more foreign permanent establishments of that same taxpayer.

This typically concerns expenses or losses that, from a Dutch tax perspective, are attributed to the head office, while from the perspective of the foreign jurisdiction they are attributed to the permanent establishment, or vice versa. As a result, the same cost base may reduce taxable profits in more than one jurisdiction.

Relevant items may include, for example, financing costs, overhead expenses, depreciation or operating losses, provided that these items are effectively deducted in more than one state. The assessment is not limited to payments made to third parties and also applies to internally allocated expenses or losses.

Answer “yes” if the same remuneration, payment, expense or loss is deducted both at head office level in the Netherlands and at the level of one or more foreign permanent establishments.

Answer “no” if each remuneration, payment, expense or loss is deducted only once within the overall structure.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('2c121efa-b0b5-4ee7-8fb3-624b09536a8a', '26', 'Is the Dutch domestic taxpayer a participant in a foreign entity that is regarded as a hybrid entity?', 'No', '28', '0.00', 'Hybrid entity', 'An entity that is regarded as a taxable entity under the laws of one State, and whose income or expenditure is treated as income or expenditure of one or more other entities or individuals under the laws of another jurisdiction.', '2025-12-29 20:51:14.295455+00', '2025-12-29 20:51:14.295455+00', 'Participation in foreign hybrid entity', false, 'This question determines whether the Dutch domestic taxpayer participates in a foreign hybrid entity within the meaning of the Dutch anti-hybrid rules.

A foreign entity is regarded as a hybrid entity if, as a result of differences in tax qualification between jurisdictions, the entity is treated as a taxable entity for a profit tax in at least one state, while its income is treated as the income of one or more participants (tax transparent) in another state.

Answer "yes" if the Dutch taxpayer holds a direct or indirect participation in a foreign entity and that entity is treated as transparent in one jurisdiction and non-transparent in another, so that income or payments may be attributed differently across states.

Answer "no" if the foreign entity is treated consistently as either transparent or non-transparent in the relevant jurisdictions and no such qualification mismatch exists.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('2d3b680b-27dc-4369-b6f3-bc90483736a9', '23c', 'Is the income allocated to the foreign permanent establishment included in a taxable base for a profit tax in the country where that permanent establishment is located?', 'Unknown', '24', '0.10', NULL, NULL, '2025-12-28 12:40:02.90026+00', '2025-12-28 12:47:29.225744+00', 'Inclusion of PE income in taxable base', false, 'This question determines whether the income that is allocated to the foreign permanent establishment is effectively taxed in the country where that permanent establishment is located.

Answer “yes” if the allocated income is included in a taxable base for a profit tax in the permanent establishment state, regardless of the applicable tax rate or the use of loss offsets.

Answer “no” if the allocated income is not included in a profit tax base in that country, for example because the permanent establishment is not recognised, the income is exempt, or the allocation is not followed for tax purposes.

This assessment must be made from the perspective of the permanent establishment state. If the income is not taxed in that jurisdiction, while it is also not taxed in the Netherlands due to allocation to the foreign permanent establishment, this may result in income not being taxed in any state and may trigger the application of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('2e23ee34-09ee-4ff2-bb06-28fd704b883a', '28', 'Has the Dutch domestic taxpayer entered into a so-called structured arrangement with a third party that has led to a double deduction or a deduction without inclusion?', 'Unknown', '29', '0.10', 'Structured arrangement', 'A structured arrangement exists where a transaction or set of transactions is designed, priced or documented in such a way that a hybrid mismatch outcome (a double deduction or a deduction without inclusion) is an integral part of the arrangement, even if the parties are not associated. In such cases, the tax benefit resulting from the hybrid mismatch is typically reflected in the terms of the arrangement, for example through pricing, profit sharing or risk allocation.', '2025-08-11 17:48:52.737035+00', '2025-12-29 11:45:21.350902+00', 'Structured arrangement', false, 'This question determines whether a potential hybrid mismatch arises from a structured arrangement involving a third party, rather than from a direct relationship between associated enterprises.

Answer “yes” if the Dutch domestic taxpayer has entered into an arrangement with a third party where:

- a double deduction or a deduction without inclusion arises, and
- that outcome can reasonably be regarded as built into or anticipated by the arrangement, regardless of whether the taxpayer intended to obtain a tax advantage.

Answer “no” if the transaction is a standard commercial arrangement with a third party and any hybrid mismatch outcome is incidental or unknown to the parties, and not reflected in the terms or pricing of the arrangement.

This question is relevant because the Dutch anti-hybrid rules also apply to hybrid mismatches arising from structured arrangements with non-associated parties. A “yes” answer therefore brings the transaction within the scope of ATAD2, even in the absence of a group relationship.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('329539b6-01e1-4ca7-92f7-633918646927', '24', 'Are there deemed payments made by a permanent establishment located outside the EU, which are in principle deductible in that country, to the Dutch domestic taxpayer (head office in the Netherlands)?', 'Yes', '25', '0.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-12-29 20:51:14.295455+00', '2025-12-29 20:51:14.295455+00', 'Deemed payment from non-EU PE to Dutch head office', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('3a58ca74-9ead-43b1-a3a5-3cc304059277', '6', 'Is at least one of these recipients a hybrid entity?', 'No', '8', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-27 20:01:40.284063+00', 'Hybrid recipient', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('3fadc81b-90f8-48d2-90cf-2daa2dc88b22', '14', 'Is the permanent establishment of the recipient recognized as such by the country where it is located?', 'Unknown', '15', '0.10', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-11 17:48:52.737035+00', '2025-12-27 20:34:24.290216+00', 'PE recognition', false, 'This question determines whether there is a mismatch in the recognition of a permanent establishment between the country of the recipient and the country where the permanent establishment is purported to be located.

Answer “yes” if the permanent establishment is recognised as such under the tax law of the country where it is located, meaning that the profits attributable to that permanent establishment are, in principle, included in a tax base for a profit tax in that country.

Answer “no” if the country where the activities are carried out does not recognise the permanent establishment, for example because it considers that no permanent establishment exists under its domestic law or an applicable tax treaty.

This question is relevant because a difference in the recognition of a permanent establishment may result in income being exempt or disregarded in one country while not being taxed in the other, potentially giving rise to a hybrid mismatch within the scope of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('44ada374-c224-4ace-9836-fce38aecca8f', '26', 'Is the Dutch domestic taxpayer a participant in a foreign entity that is regarded as a hybrid entity?', 'Unknown', '28', '0.10', 'Hybrid entity', 'An entity that is regarded as a taxable entity under the laws of one State, and whose income or expenditure is treated as income or expenditure of one or more other entities or individuals under the laws of another jurisdiction.', '2025-08-11 17:48:52.737035+00', '2025-12-28 13:04:05.547569+00', 'Participation in foreign hybrid entity', false, 'This question determines whether the Dutch domestic taxpayer participates in a foreign hybrid entity within the meaning of the Dutch anti-hybrid rules.

A foreign entity is regarded as a hybrid entity if, as a result of differences in tax qualification between jurisdictions, the entity is treated as a taxable entity for a profit tax in at least one state, while its income is treated as the income of one or more participants (tax transparent) in another state.

Answer “yes” if the Dutch taxpayer holds a direct or indirect participation in a foreign entity and that entity is treated as transparent in one jurisdiction and non-transparent in another, so that income or payments may be attributed differently across states.

Answer “no” if the foreign entity is treated consistently as either transparent or non-transparent in the relevant jurisdictions and no such qualification mismatch exists.

');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('45010b1e-4d40-461a-8a9c-70432d6a1cdb', '3', 'Is the Dutch domestic taxpayer part of an international structure?', 'Yes', '4', '0.00', '', '', '2025-08-03 16:49:21.766755+00', '2025-12-29 11:45:50.503711+00', 'International structure', true, 'This question determines whether the taxpayer forms part of a cross-border or international structure, which is relevant because most hybrid mismatches within the scope of the Dutch anti-hybrid rules (ATAD2) arise in a cross-border context.

Answer “yes” if the Dutch domestic taxpayer is part of an international structure. This includes, in particular, situations where the taxpayer:

- has one or more foreign parent companies, subsidiaries or sister companies, or
- is otherwise part of a group with activities, entities or permanent establishments outside the Netherlands.

The presence of any cross-border element within the group or structure is sufficient to answer this question with “yes”.

Answer “no” if the taxpayer operates exclusively within the Netherlands and is not part of any group or structure with foreign entities, foreign permanent establishments or other cross-border elements.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('48e17d84-5d4a-475c-b729-5ba58547178e', '26', 'Is the Dutch domestic taxpayer a participant in a foreign entity that is regarded as a hybrid entity?', 'Yes', '27', '0.00', 'Hybrid entity', 'An entity that is regarded as a taxable entity under the laws of one State, and whose income or expenditure is treated as income or expenditure of one or more other entities or individuals under the laws of another jurisdiction.', '2025-08-03 16:49:21.766755+00', '2025-12-28 13:04:06.966268+00', 'Participation in foreign hybrid entity', true, 'This question determines whether the Dutch domestic taxpayer participates in a foreign hybrid entity within the meaning of the Dutch anti-hybrid rules.

A foreign entity is regarded as a hybrid entity if, as a result of differences in tax qualification between jurisdictions, the entity is treated as a taxable entity for a profit tax in at least one state, while its income is treated as the income of one or more participants (tax transparent) in another state.

Answer “yes” if the Dutch taxpayer holds a direct or indirect participation in a foreign entity and that entity is treated as transparent in one jurisdiction and non-transparent in another, so that income or payments may be attributed differently across states.

Answer “no” if the foreign entity is treated consistently as either transparent or non-transparent in the relevant jurisdictions and no such qualification mismatch exists.

');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('49372168-e21a-4f43-bb24-2eba0caf583b', '34', 'Is the deemed payment (see previous question) included in the taxable base of the other party, being the foreign head office or one of its permanent establishments?', 'Unknown', '35', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-28 20:20:39.123216+00', NULL, false, 'Answer “yes” if the deemed payment is included in a taxable base for a profit tax in the jurisdiction of the foreign head office or the relevant permanent establishment, regardless of the applicable tax rate or the availability of loss relief.

Answer “no” if the deemed payment is not included in a profit tax base at the level of the other party, for example because internal dealings are disregarded, the permanent establishment is not recognised, or the allocation is not followed for tax purposes.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('4a171527-80f6-4d4b-998c-1b6b5c062579', '11', 'Is the corresponding income from these payments effectively included in a taxable base for a profit tax, or otherwise neutralised under rules comparable to Articles 12aa or 12ab, in the jurisdiction(s) where the payment ultimately results in a deduction?', 'Unknown', '12', '0.10', 'Inclusion', 'Inclusion is present if a remuneration, payment or deemed payment is included in a tax on income, even if this could be offset against future losses. If the remuneration, payment or deemed payment is eligible for a tax exemption, there is no inclusion.', '2025-08-11 17:48:52.737035+00', '2025-12-27 20:32:26.029387+00', 'Exclusion from tax', false, 'This question determines whether a potential hybrid mismatch funded by the payment is already neutralised outside the Netherlands.

Answer “yes” if, in at least one of the jurisdictions involved in the transaction or series of transactions, a measure is applied that is comparable to the Dutch anti-hybrid rules (Articles 12aa or 12ab), or if the corresponding income is otherwise effectively included in a profit tax base.

Answer “no” if no such inclusion or equivalent adjustment takes place, meaning that the hybrid mismatch remains uncorrected in the relevant foreign jurisdiction(s).');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('4b4f545a-73a3-447f-9504-f4d760e701eb', '25', 'Is the corresponding income from the deemed payment included in the Dutch tax base of the Dutch domestic taxpayer?', 'No', '26', '1.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-08-03 16:49:21.766755+00', '2025-08-26 17:30:49.962771+00', 'Inclusion of deemed payment in Dutch tax base', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('4bc24ab5-e095-4d3d-9bab-3076fdcbfc2f', '25', 'Is the corresponding income from the deemed payment included in the Dutch tax base of the Dutch domestic taxpayer?', 'Yes', '26', '0.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-12-29 20:51:14.295455+00', '2025-12-29 20:51:14.295455+00', 'Inclusion of deemed payment in Dutch tax base', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('50ac2524-b964-4392-b511-3ed10e0c1cec', '8', 'Is the corresponding income at the level of the recipient included in a tax base for a profit tax within a reasonable period after the deduction is claimed in the Netherlands?', 'Unknown', '9', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-30 10:24:33.389635+00', NULL, false, 'This question assesses whether the income corresponding to a deductible payment is included, within a reasonable period, in a tax base for a profit tax as required under the ATAD2 rules, taking into account the hybrid nature of the arrangement.

The relevance of this question is limited to situations where a hybrid element is present, such as:
- a hybrid financial instrument, or
- a payment or remuneration whose tax treatment differs between jurisdictions due to differences in legal or tax qualification.

Income is regarded as included in a tax base for a profit tax if the income is taken into account under the recipient’s tax law in a tax on profits within a reasonable period after the deduction is claimed in the Netherlands.

Income is considered not included for the purposes of this question if the non-inclusion is the direct result of a hybrid mismatch, for example where:
- the payment is treated as a non-taxable return on capital in the recipient jurisdiction due to a different qualification of the instrument, or
- the payment is disregarded because the recipient treats the payer as tax transparent, or
- the income is allocated elsewhere under the recipient’s tax law as a consequence of a qualification mismatch.

By contrast, this question does not focus on cases where income is not taxed for reasons unrelated to hybrid mismatches, such as:
- general tax exemptions not linked to the qualification of the instrument or payment, or
- the mere absence of sufficient taxable profits due to losses.

Similarly, the existence of withholding tax, loss offset, group consolidation or a generally applicable reduced profit tax regime does not, in itself, determine the outcome of this question, unless the treatment results from the same hybrid qualification that gives rise to the deduction in the Netherlands.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('524dc2c1-ffa8-423c-b422-fbf15c42ac9c', '31', 'Is the foreign head office of the Dutch permanent establishment located outside the EU?', 'Yes', '32', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-08-26 17:30:49.962771+00', 'Non-EU head office', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('527a0e51-46b4-4998-85b8-5173aa340742', '20b', 'Is there a deemed payment, which is in principle deductible in the Netherlands, to one or more foreign permanent establishments?', 'Yes', '21b', '0.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-08-03 16:49:21.766755+00', '2025-08-26 17:30:49.962771+00', 'Deemed payment to PE', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('546774aa-5338-4dd8-923f-6c9f0f637bb8', '11', 'Is the corresponding income from these payments effectively included in a taxable base for a profit tax, or otherwise neutralised under rules comparable to Articles 12aa or 12ab, in the jurisdiction(s) where the payment ultimately results in a deduction?', 'No', '12', '1.00', 'Inclusion', 'Inclusion is present if a remuneration, payment or deemed payment is included in a tax on income, even if this could be offset against future losses. If the remuneration, payment or deemed payment is eligible for a tax exemption, there is no inclusion.', '2025-08-03 16:49:21.766755+00', '2025-12-30 11:00:42.324245+00', 'Exclusion from tax', true, 'This question determines whether a potential hybrid mismatch funded by the payment is already neutralised outside the Netherlands.

Answer “yes” if, in at least one of the jurisdictions involved in the transaction or series of transactions, a measure is applied that is comparable to the Dutch anti-hybrid rules (Articles 12aa or 12ab), or if the corresponding income is otherwise effectively included in a profit tax base.

Answer “no” if no such inclusion or equivalent adjustment takes place, meaning that the hybrid mismatch remains uncorrected in the relevant foreign jurisdiction(s).');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('594832ac-bdb2-4875-acc9-4d15fdb3c629', '2', 'Is the taxpayer a legal entity that is not a resident of the Netherlands, but is subject to Dutch corporate income tax as a non-resident taxpayer because it has a permanent establishment in the Netherlands?', 'Unknown', '3', '0.10', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-11 17:48:52.737035+00', '2025-12-27 19:15:01.896306+00', 'Non-resident taxpayer', false, 'This question determines whether the taxpayer falls within the scope of Dutch corporate income tax as a non-resident taxpayer and therefore whether the Dutch anti-hybrid rules (ATAD2) may apply.

Answer “yes” if the taxpayer qualifies as a Dutch non-resident corporate income taxpayer under Article 3 of the Dutch Corporate Income Tax Act. This includes, in particular:

entities that are not tax resident in the Netherlands, but that derive Dutch-source income through a permanent establishment in the Netherlands within the meaning of Dutch tax law or an applicable tax treaty, and are therefore subject to Dutch corporate income tax with respect to the profits attributable to that permanent establishment.

Answer “no” if the taxpayer does not have a permanent establishment in the Netherlands and is therefore not treated as a Dutch non-resident corporate income taxpayer under Dutch tax law.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('5dfc024b-5e39-44eb-857a-bfba8d0e0f35', '32', 'Does the foreign head office (located outside the EU) make payments or provide remunerations that are, in principle, deductible both at its own level and at the level of the Dutch permanent establishment?', 'Unknown', '33', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:51.967418+00', 'Double deduction HO+PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('6090aebb-dbd3-4f5f-a98e-0e1d8613d1b1', '4', 'Are any of the shareholder(s) or participant(s) an associated enterprise of the Dutch entity that, based on their own local tax law, treat the Dutch entity as a separate taxable entity (non-transparent), while the Netherlands treats it as tax transparent?', 'Unknown', '4b', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-29 20:32:23.193535+00', NULL, false, 'For the purpose of this question, the Dutch entity (typically a partnership such as a CV, VOF or maatschap) is treated as tax transparent in the Netherlands, meaning its income, expenses and losses are attributed directly to its participants. A reverse-hybrid classification conflict arises where an associated shareholder or participant, under its own local tax law, instead treats that same Dutch entity as a separate taxable entity (non-transparent), so that its income is not currently taxed at either level. Article 2 paragraph 11 CIT Act then treats the Dutch entity itself as a Dutch taxpayer.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('61d2acc3-8ee2-4836-b961-a5f0f1b30a6f', '30', 'Has the Dutch domestic taxpayer transferred a financial instrument to a party in another country, and is the Dutch taxpayer considered the owner of the returns under Dutch tax law, while the other party is considered the owner of the same returns under the tax law of the other country?', 'No', 'end', '0.00', 'Financial instrument', 'Any instrument that leads to a revenue on a loan or comparable agreement or on equity, and includes a hybrid transfer.', '2025-08-03 16:49:21.766755+00', '2025-12-29 11:46:13.647072+00', 'Hybrid transfer', false, 'This question determines whether the Dutch domestic taxpayer is involved in a hybrid transfer of a financial instrument, where different jurisdictions attribute the same return on that instrument to different parties.

A hybrid transfer arises where a financial instrument (such as shares, bonds or similar instruments) is transferred to a party in another country, but the tax laws of the involved jurisdictions do not agree on who is entitled to the economic return (for example interest or dividends). As a result, both jurisdictions may treat a different party as the owner of the same return for tax purposes.

Answer “yes” if:

- the Dutch domestic taxpayer has transferred a financial instrument to a party in another country, and
- under Dutch tax law, the Dutch taxpayer is still regarded as the owner of the returns on that instrument, while
- under the tax law of the other country, the counterparty is regarded as the owner of those same returns.

In such a case, the same return may be taken into account by more than one taxpayer or may give rise to a deduction without corresponding inclusion, which can result in a hybrid mismatch within the scope of the Dutch anti-hybrid rules.

Answer “no” if:
- both jurisdictions attribute the returns on the financial instrument to the same party, or
- the transfer does not affect the tax ownership of the returns in a way that leads to a qualification mismatch.
');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('63fa5566-cbff-4a98-8a82-2397ec9a40d8', '23b', 'Is the received amount (partially) allocated to a foreign permanent establishment of the Dutch domestic taxpayer, and therefore not fully included in the Dutch tax base?', 'Yes', '23c', '0.00', 'Example 2', 'Imagine a situation where an associated (hybrid entity) enterprise outside of the EU makes a payment to a taxpayer. Based on the local tax laws in the foreign country, the payment is considered to have been paid to the taxpayer. The payment is deductible in that country. The taxpayer (partially) allocates the payment to a foreign PE. Now imagine that this payment is not taxed in the country of the PE. In such a case, there is deduction without inclusion due to a hybrid mismatch at the level of the PE. The taxpayer must report income to the amount of the benefit.', '2025-08-03 16:49:21.766755+00', '2025-12-28 12:41:01.789306+00', 'Allocation of inbound payment to foreign PE', true, 'This question determines whether the income received by the Dutch domestic taxpayer is wholly or partly attributed to a foreign permanent establishment, as a result of which that income is not fully included in the Dutch tax base.

Answer “yes” if, under Dutch tax law and applicable tax treaties, the received amount is (partly) allocated to a foreign permanent establishment of the taxpayer and therefore falls outside the Dutch taxable profit, for example because the foreign permanent establishment’s profits are exempt under the object exemption.

Answer “no” if the received amount is fully included in the Dutch tax base and no part of the income is attributed to a foreign permanent establishment.

This question is relevant because allocating income to a foreign permanent establishment may result in the income not being taxed in the Netherlands, which requires further assessment under the Dutch anti-hybrid rules to determine whether the income is taxed in the state of the permanent establishment or gives rise to a hybrid mismatch.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('648d69ac-f86e-45bb-ba87-98951f12f855', '30', 'Has the Dutch domestic taxpayer transferred a financial instrument to a party in another country, and is the Dutch taxpayer considered the owner of the returns under Dutch tax law, while the other party is considered the owner of the same returns under the tax law of the other country?', 'Unknown', 'end', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-29 11:46:23.738326+00', 'Hybrid transfer', false, 'This question determines whether the Dutch domestic taxpayer is involved in a hybrid transfer of a financial instrument, where different jurisdictions attribute the same return on that instrument to different parties.

A hybrid transfer arises where a financial instrument (such as shares, bonds or similar instruments) is transferred to a party in another country, but the tax laws of the involved jurisdictions do not agree on who is entitled to the economic return (for example interest or dividends). As a result, both jurisdictions may treat a different party as the owner of the same return for tax purposes.

Answer “yes” if:

- the Dutch domestic taxpayer has transferred a financial instrument to a party in another country, and
- under Dutch tax law, the Dutch taxpayer is still regarded as the owner of the returns on that instrument, while
- under the tax law of the other country, the counterparty is regarded as the owner of those same returns.

In such a case, the same return may be taken into account by more than one taxpayer or may give rise to a deduction without corresponding inclusion, which can result in a hybrid mismatch within the scope of the Dutch anti-hybrid rules.

Answer “no” if:
- both jurisdictions attribute the returns on the financial instrument to the same party, or
- the transfer does not affect the tax ownership of the returns in a way that leads to a qualification mismatch.
');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('69ae3e88-c393-4728-9723-085cb82c24bc', '32', 'Does the foreign head office (located outside the EU) make payments or provide remunerations that are, in principle, deductible both at its own level and at the level of the Dutch permanent establishment?', 'No', '33', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-08-04 18:53:04.196731+00', 'Double deduction HO+PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('6b5062e4-2a20-4d11-b0de-bd30ca730cab', '5', 'Does the Dutch domestic taxpayer make payments or provide remunerations to an associated enterprise (referred to as ''recipient'' in the following questions), which are in principle deductible for Dutch tax purposes?', 'Unknown', '15', '0.10', '', '', '2025-08-11 17:48:52.737035+00', '2025-12-27 20:15:36.046513+00', NULL, false, 'The concept of a payment or remuneration is interpreted broadly and goes beyond amounts that are actually paid in cash.

It includes both payments that are factually made, such as interest, royalties or payments under financial instruments, and payments or remunerations that are deemed to be made for tax purposes. This also covers amounts that arise as a result of tax adjustments, including transfer pricing corrections or comparable foreign tax rules, even if no actual payment has taken place.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('6c3103bd-d0e1-4594-83e9-bc6389364fd0', '32', 'Does the foreign head office (located outside the EU) make payments or provide remunerations that are, in principle, deductible both at its own level and at the level of the Dutch permanent establishment?', 'Yes', '33', '1.00', 'Example 4', 'This could be a payment of interest on a loan concluded by the head office as a means of financing assets of the permanent establishment. Based on Dutch tax law, (a part of) this interest is allocated to the permanent establishment in the Netherlands. If the interest is also fully deductible at the level of the head office, (partial) double deduction may occur.', '2025-08-03 16:49:21.766755+00', '2025-08-26 17:30:49.962771+00', 'Double deduction HO+PE', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('6e3dc822-e2a8-46eb-8691-122f65bb364d', '31', 'Is the foreign head office of the Dutch permanent establishment located outside the EU?', 'No', '33', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-08-12 14:33:29.915717+00', 'Non-EU head office', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('718a7e84-b057-4e5c-ad89-f4e57156ba40', '12', 'Does the recipient have a permanent establishment?', 'Unknown', '15', '0.10', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:24.268352+00', 'Recipient has PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('72edab55-518d-4877-95da-75304cd47973', '25', 'Is the corresponding income from the deemed payment included in the Dutch tax base of the Dutch domestic taxpayer?', 'Unknown', '26', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:43.445126+00', 'Inclusion of deemed payment in Dutch tax base', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('73c13d0c-0392-42b9-b53f-0b30a0095040', '22b', 'Does the Dutch domestic taxpayer receive payments or remunerations from an associated enterprise located outside the EU, which are in principle deductible for tax purposes in that non-EU country?', 'Unknown', '26', '0.10', 'Associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-08-11 17:48:52.737035+00', '2025-12-28 12:33:11.159022+00', 'Inbound payment from non-EU associated enterprise', false, 'This question determines whether the Dutch domestic taxpayer receives payments or remunerations from an associated enterprise that is located outside the European Union, where those payments are, in principle, deductible for tax purposes in the payer’s jurisdiction.

Answer “yes” if an associated enterprise resident in a non-EU country makes payments or provides remunerations to the Dutch taxpayer that reduce its taxable profit under a tax on profits in that country, regardless of whether the deduction is actually used in a specific year.

Answer “no” if the payments are not deductible in the payer’s jurisdiction, or if the payer is resident within the European Union.

This question is relevant because, where a non-EU payer deducts a payment and no comparable anti-hybrid rules apply in that jurisdiction, the Netherlands may be required to apply the secondary ATAD2 rule if the corresponding income is not effectively included in a taxable base elsewhere.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('73e78c64-f9c5-4898-bd4b-2c1c50bdb1f2', '12', 'Does the recipient have a permanent establishment?', 'Yes', '13', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-08-26 17:30:49.962771+00', 'Recipient has PE', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('7aa0279b-2161-478f-bad7-d24ee7a82341', '18b', 'Are all of those foreign permanent establishments recognised as permanent establishments by the countries in which they are located?', 'No', '19', '1.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-30 11:01:08.174506+00', 'Recognition of foreign PEs', true, 'This question determines whether the foreign permanent establishments identified in the previous question are also recognised as permanent establishments under the tax law of the countries in which they are located.

Answer “yes” if each foreign jurisdiction in which activities are carried out recognises the presence as a permanent establishment under its domestic tax law and any applicable tax treaty.

Answer “no” if one or more of those jurisdictions does not recognise the presence as a permanent establishment, even though it qualifies as such from a Dutch tax perspective.

This question must be assessed from the perspective of the foreign country concerned. Differences in recognition between the Netherlands and the foreign jurisdiction may give rise to a hybrid permanent establishment mismatch within the scope of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('7b4a3287-db13-48f2-ac2b-ca6eeae10bca', '3', 'Is the Dutch domestic taxpayer part of an international structure?', 'Unknown', '4', '0.10', '', '', '2025-08-11 17:48:52.737035+00', '2025-12-29 11:45:48.12772+00', 'International structure', false, 'This question determines whether the taxpayer forms part of a cross-border or international structure, which is relevant because most hybrid mismatches within the scope of the Dutch anti-hybrid rules (ATAD2) arise in a cross-border context.

Answer “yes” if the Dutch domestic taxpayer is part of an international structure. This includes, in particular, situations where the taxpayer:

- has one or more foreign parent companies, subsidiaries or sister companies, or
- is otherwise part of a group with activities, entities or permanent establishments outside the Netherlands.

The presence of any cross-border element within the group or structure is sufficient to answer this question with “yes”.

Answer “no” if the taxpayer operates exclusively within the Netherlands and is not part of any group or structure with foreign entities, foreign permanent establishments or other cross-border elements.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('7b6933b2-dc0d-485c-bbe7-72c66730fd19', '5', 'Does the Dutch domestic taxpayer make payments or provide remunerations to an associated enterprise (referred to as ''recipient'' in the following questions), which are in principle deductible for Dutch tax purposes?', 'Yes', '6', '0.00', 'associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-08-03 16:49:21.766755+00', '2025-12-27 20:15:31.121654+00', 'Associated payments', true, 'The concept of a payment or remuneration is interpreted broadly and goes beyond amounts that are actually paid in cash.

It includes both payments that are factually made, such as interest, royalties or payments under financial instruments, and payments or remunerations that are deemed to be made for tax purposes. This also covers amounts that arise as a result of tax adjustments, including transfer pricing corrections or comparable foreign tax rules, even if no actual payment has taken place.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('7d3d3984-3586-47b6-ba69-1611769f6523', '34', 'Is the deemed payment (see previous question) included in the taxable base of the other party, being the foreign head office or one of its permanent establishments?', 'Yes', '35', '0.00', 'Example 5', 'The balance sheet of a foreign head office includes a mobile installation. This installation is temporarily made available to a PE in the Netherlands. The remuneration (i.e. the deemed payment) involved, is in principle deductible from the PE profit in the Netherlands. Due to the fact that the remuneration (the deemed payment) is not included in the profit of the head office based on local tax legislation, a mismatch occurs. In this case, the remuneration (deemed payment) is not deductible from the PE profit in the Netherlands.', '2025-08-03 16:49:21.766755+00', '2025-12-28 20:20:41.402085+00', 'Inclusion of deemed payment by foreign head office or PE', false, 'Answer “yes” if the deemed payment is included in a taxable base for a profit tax in the jurisdiction of the foreign head office or the relevant permanent establishment, regardless of the applicable tax rate or the availability of loss relief.

Answer “no” if the deemed payment is not included in a profit tax base at the level of the other party, for example because internal dealings are disregarded, the permanent establishment is not recognised, or the allocation is not followed for tax purposes.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('7e6e1282-cae7-413f-96a4-088be2673d92', '18b', 'Are all of those foreign permanent establishments recognised as permanent establishments by the countries in which they are located?', 'Unknown', '19', '0.10', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-11 17:48:52.737035+00', '2025-12-28 10:53:34.136324+00', 'Recognition of foreign PEs', false, 'This question determines whether the foreign permanent establishments identified in the previous question are also recognised as permanent establishments under the tax law of the countries in which they are located.

Answer “yes” if each foreign jurisdiction in which activities are carried out recognises the presence as a permanent establishment under its domestic tax law and any applicable tax treaty.

Answer “no” if one or more of those jurisdictions does not recognise the presence as a permanent establishment, even though it qualifies as such from a Dutch tax perspective.

This question must be assessed from the perspective of the foreign country concerned. Differences in recognition between the Netherlands and the foreign jurisdiction may give rise to a hybrid permanent establishment mismatch within the scope of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('801f7412-b0a6-484e-aa25-5c110e0aeb6c', '14', 'Is the permanent establishment of the recipient recognized as such by the country where it is located?', 'No', '15', '1.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-27 20:34:22.306165+00', 'PE recognition', true, 'This question determines whether there is a mismatch in the recognition of a permanent establishment between the country of the recipient and the country where the permanent establishment is purported to be located.

Answer “yes” if the permanent establishment is recognised as such under the tax law of the country where it is located, meaning that the profits attributable to that permanent establishment are, in principle, included in a tax base for a profit tax in that country.

Answer “no” if the country where the activities are carried out does not recognise the permanent establishment, for example because it considers that no permanent establishment exists under its domestic law or an applicable tax treaty.

This question is relevant because a difference in the recognition of a permanent establishment may result in income being exempt or disregarded in one country while not being taxed in the other, potentially giving rise to a hybrid mismatch within the scope of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('849ef3f5-57cb-4785-bf50-9d60cb9c32ff', '21b', 'Is this deemed payment disregarded for tax purposes in the country where the permanent establishment is located?', 'Yes', '22b', '1.00', 'Example 1', 'The taxpayer (head office) has a permanent establishment abroad, in which IP has been developed. The Dutch head office makes a deemed royalty payment for this IP to the foreign PE, which is deductible for Dutch tax purposes. The corresponding royalty revenue is not taken into account in the country of the PE, and is therefore not subject to taxation. ', '2025-08-03 16:49:21.766755+00', '2025-12-28 11:04:52.342627+00', 'Disregarded deemed payment at PE level', true, 'This question determines whether a deemed or notional payment between the head office and the permanent establishment is ignored (disregarded) for tax purposes in the country where the permanent establishment is located.

A deemed payment is regarded as disregarded if, under the tax law or treaty practice of the permanent establishment state, internal dealings between a head office and its permanent establishment are not recognised as taxable transactions. This is typically the case where the permanent establishment state:

does not recognise internal interest, royalties or service charges between a head office and its permanent establishment,

determines the taxable profit of the permanent establishment solely on the basis of an overall profit allocation, without recognising internal transactions, or

treats the head office and the permanent establishment as a single taxpayer for purposes of profit taxation.

Answer “yes” if the deemed payment is ignored for tax purposes in the permanent establishment state and therefore does not give rise to taxable income at the level of the permanent establishment.

Answer “no” if the permanent establishment state does recognise such deemed payments and includes them in the determination of the taxable profit of the permanent establishment.

This assessment must be made from the perspective of the permanent establishment state');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('8e44de4c-5208-487a-a121-041118a3a624', '24', 'Are there deemed payments made by a permanent establishment located outside the EU, which are in principle deductible in that country, to the Dutch domestic taxpayer (head office in the Netherlands)?', 'No', '26', '0.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-08-03 16:49:21.766755+00', '2025-08-04 18:53:04.196731+00', 'Deemed payment from non-EU PE to Dutch head office', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('944d7306-cb26-4a1b-a548-f8f4b2bec505', '12', 'Does the recipient have a permanent establishment?', 'No', '15', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-08-12 14:21:48.487495+00', 'Recipient has PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('9730e678-6159-4a8f-8eb6-05cd95b07b54', '20b', 'Is there a deemed payment, which is in principle deductible in the Netherlands, to one or more foreign permanent establishments?', 'No', '22b', '0.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-08-03 16:49:21.766755+00', '2025-12-28 11:00:50.908786+00', 'Deemed payment to PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('998dc059-2289-48be-8207-3a0ea01ff0ae', '8', 'Is the corresponding income at the level of the recipient included in a tax base for a profit tax within a reasonable period after the deduction is claimed in the Netherlands?', 'Yes', '9', '0.00', 'reasonable period', 'For the purposes of the reasonable period test, income is considered to be included in time if it is taken into account in a profit tax base in the recipient state in a tax year that begins within twelve months after the end of the tax year of the Dutch taxpayer in which the deduction is claimed.

If this twelve-month condition is not met, income may still be regarded as included within a reasonable period if it can reasonably be expected that the income will be included in a future tax year in a profit tax base and the payment terms reflect conditions that would have been agreed between independent parties. In that case, factors such as the arm’s length nature of the instrument, the interest rate, the maturity, and the repayment terms are relevant.', '2025-08-03 16:49:21.766755+00', '2025-12-30 10:24:19.759879+00', 'Inclusion in recipient state', false, 'This question assesses whether the income corresponding to a deductible payment is included, within a reasonable period, in a tax base for a profit tax as required under the ATAD2 rules, taking into account the hybrid nature of the arrangement.

The relevance of this question is limited to situations where a hybrid element is present, such as:
- a hybrid financial instrument, or
- a payment or remuneration whose tax treatment differs between jurisdictions due to differences in legal or tax qualification.

Income is regarded as included in a tax base for a profit tax if the income is taken into account under the recipient’s tax law in a tax on profits within a reasonable period after the deduction is claimed in the Netherlands.

Income is considered not included for the purposes of this question if the non-inclusion is the direct result of a hybrid mismatch, for example where:
- the payment is treated as a non-taxable return on capital in the recipient jurisdiction due to a different qualification of the instrument, or
- the payment is disregarded because the recipient treats the payer as tax transparent, or
- the income is allocated elsewhere under the recipient’s tax law as a consequence of a qualification mismatch.

By contrast, this question does not focus on cases where income is not taxed for reasons unrelated to hybrid mismatches, such as:
- general tax exemptions not linked to the qualification of the instrument or payment, or
- the mere absence of sufficient taxable profits due to losses.

Similarly, the existence of withholding tax, loss offset, group consolidation or a generally applicable reduced profit tax regime does not, in itself, determine the outcome of this question, unless the treatment results from the same hybrid qualification that gives rise to the deduction in the Netherlands.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('9c433a19-ea03-4d11-8ba7-53f1ffa4d5f1', '6', 'Is at least one of these recipients a hybrid entity?', 'Yes', '8', '1.00', 'Hybrid entity', 'An entity that is regarded as a taxable entity under the laws of one State, and whose income or expenditure is treated as income or expenditure of one or more other entities or individuals under the laws of another jurisdiction.', '2025-08-03 16:49:21.766755+00', '2025-12-27 20:01:45.999616+00', 'Hybrid recipient', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('9c7031be-f194-4b76-be7a-d54c1e0f54d6', '8', 'Is the corresponding income at the level of the recipient included in a tax base for a profit tax within a reasonable period after the deduction is claimed in the Netherlands?', 'No', '9', '1.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-30 10:24:35.189281+00', 'Inclusion in recipient state', true, 'This question assesses whether the income corresponding to a deductible payment is included, within a reasonable period, in a tax base for a profit tax as required under the ATAD2 rules, taking into account the hybrid nature of the arrangement.

The relevance of this question is limited to situations where a hybrid element is present, such as:
- a hybrid financial instrument, or
- a payment or remuneration whose tax treatment differs between jurisdictions due to differences in legal or tax qualification.

Income is regarded as included in a tax base for a profit tax if the income is taken into account under the recipient’s tax law in a tax on profits within a reasonable period after the deduction is claimed in the Netherlands.

Income is considered not included for the purposes of this question if the non-inclusion is the direct result of a hybrid mismatch, for example where:
- the payment is treated as a non-taxable return on capital in the recipient jurisdiction due to a different qualification of the instrument, or
- the payment is disregarded because the recipient treats the payer as tax transparent, or
- the income is allocated elsewhere under the recipient’s tax law as a consequence of a qualification mismatch.

By contrast, this question does not focus on cases where income is not taxed for reasons unrelated to hybrid mismatches, such as:
- general tax exemptions not linked to the qualification of the instrument or payment, or
- the mere absence of sufficient taxable profits due to losses.

Similarly, the existence of withholding tax, loss offset, group consolidation or a generally applicable reduced profit tax regime does not, in itself, determine the outcome of this question, unless the treatment results from the same hybrid qualification that gives rise to the deduction in the Netherlands.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a0e94120-7690-44fa-8249-80e5cd4e3e81', '28', 'Has the Dutch domestic taxpayer entered into a so-called structured arrangement with a third party that has led to a double deduction or a deduction without inclusion?', 'No', '29', '0.00', 'Structured arrangement', 'A structured arrangement exists where a transaction or set of transactions is designed, priced or documented in such a way that a hybrid mismatch outcome (a double deduction or a deduction without inclusion) is an integral part of the arrangement, even if the parties are not associated. In such cases, the tax benefit resulting from the hybrid mismatch is typically reflected in the terms of the arrangement, for example through pricing, profit sharing or risk allocation.', '2025-08-03 16:49:21.766755+00', '2025-12-29 11:45:07.9751+00', 'Structured arrangement', false, 'This question determines whether a potential hybrid mismatch arises from a structured arrangement involving a third party, rather than from a direct relationship between associated enterprises.

Answer “yes” if the Dutch domestic taxpayer has entered into an arrangement with a third party where:

- a double deduction or a deduction without inclusion arises, and
- that outcome can reasonably be regarded as built into or anticipated by the arrangement, regardless of whether the taxpayer intended to obtain a tax advantage.

Answer “no” if the transaction is a standard commercial arrangement with a third party and any hybrid mismatch outcome is incidental or unknown to the parties, and not reflected in the terms or pricing of the arrangement.

This question is relevant because the Dutch anti-hybrid rules also apply to hybrid mismatches arising from structured arrangements with non-associated parties. A “yes” answer therefore brings the transaction within the scope of ATAD2, even in the absence of a group relationship.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a1b2c3d4-1111-4111-8111-111111111111', '4b', 'Does the Dutch taxpayer make payments or provide remunerations to that shareholder or participant that are, in principle, deductible for Dutch tax purposes and that are not included in the taxable base of that shareholder or participant under the tax law of the recipient''s jurisdiction?', 'Yes', '4c', '1.00', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:02:11.269495+00', 'Deductible payment to transparent shareholder', true, 'This question aims to identify situations in which the Dutch taxpayer claims a tax deduction for a payment or remuneration, while the corresponding amount is not included in the taxable base of the shareholder or participant, as a result of differences in tax qualification between jurisdictions. Such situations may give rise to a deduction without inclusion within the meaning of the ATAD2 hybrid mismatch rules.

The term payments or remunerations should be interpreted broadly. It includes any other remuneration that is, in principle, deductible for Dutch corporate income tax purposes.

A payment or remuneration is considered not included in the taxable base if, under the tax law of the recipient’s jurisdiction, the corresponding income is not taken into account for the purposes of a tax on profits or income. For this question, it is relevant that the non-inclusion of the payment results from a difference in tax qualification between the Netherlands and the recipient’s jurisdiction. Situations in which the income is not taxed for reasons unrelated to hybrid mismatches (such as a general exemption regime or the absence of a profit tax) are not the primary focus of this question.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a1b2c3d4-1111-4111-8111-111111111112', '4b', 'Does the Dutch taxpayer make payments or provide remunerations to that shareholder or participant that are, in principle, deductible for Dutch tax purposes and that are not included in the taxable base of that shareholder or participant under the tax law of the recipient''s jurisdiction?', 'No', '4c', '0.00', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:01:59.237599+00', 'Deductible payment to transparent shareholder', false, 'This question aims to identify situations in which the Dutch taxpayer claims a tax deduction for a payment or remuneration, while the corresponding amount is not included in the taxable base of the shareholder or participant, as a result of differences in tax qualification between jurisdictions. Such situations may give rise to a deduction without inclusion within the meaning of the ATAD2 hybrid mismatch rules.

The term payments or remunerations should be interpreted broadly. It includes any other remuneration that is, in principle, deductible for Dutch corporate income tax purposes.

A payment or remuneration is considered not included in the taxable base if, under the tax law of the recipient’s jurisdiction, the corresponding income is not taken into account for the purposes of a tax on profits or income. For this question, it is relevant that the non-inclusion of the payment results from a difference in tax qualification between the Netherlands and the recipient’s jurisdiction. Situations in which the income is not taxed for reasons unrelated to hybrid mismatches (such as a general exemption regime or the absence of a profit tax) are not the primary focus of this question.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a1b2c3d4-1111-4111-8111-111111111113', '4b', 'Does the Dutch taxpayer make payments or provide remunerations to that shareholder or participant that are, in principle, deductible for Dutch tax purposes and that are not included in the taxable base of that shareholder or participant under the tax law of the recipient''s jurisdiction?', 'Unknown', '4c', '0.10', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:02:09.340775+00', 'Deductible payment to transparent shareholder', false, 'This question aims to identify situations in which the Dutch taxpayer claims a tax deduction for a payment or remuneration, while the corresponding amount is not included in the taxable base of the shareholder or participant, as a result of differences in tax qualification between jurisdictions. Such situations may give rise to a deduction without inclusion within the meaning of the ATAD2 hybrid mismatch rules.

The term payments or remunerations should be interpreted broadly. It includes any other remuneration that is, in principle, deductible for Dutch corporate income tax purposes.

A payment or remuneration is considered not included in the taxable base if, under the tax law of the recipient’s jurisdiction, the corresponding income is not taken into account for the purposes of a tax on profits or income. For this question, it is relevant that the non-inclusion of the payment results from a difference in tax qualification between the Netherlands and the recipient’s jurisdiction. Situations in which the income is not taxed for reasons unrelated to hybrid mismatches (such as a general exemption regime or the absence of a profit tax) are not the primary focus of this question.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a36d3bba-aac9-40f9-81a2-35e3e7b96068', '11', 'Is the corresponding income from these payments effectively included in a taxable base for a profit tax, or otherwise neutralised under rules comparable to Articles 12aa or 12ab, in the jurisdiction(s) where the payment ultimately results in a deduction?', 'Yes', '12', '0.00', 'Inclusion', 'Inclusion is present if a remuneration, payment or deemed payment is included in a tax on income, even if this could be offset against future losses. If the remuneration, payment or deemed payment is eligible for a tax exemption, there is no inclusion.', '2025-08-03 16:49:21.766755+00', '2025-12-29 21:46:31.124476+00', 'Exclusion from tax', true, 'This question determines whether a potential hybrid mismatch funded by the payment is already neutralised outside the Netherlands.

Answer “yes” if, in at least one of the jurisdictions involved in the transaction or series of transactions, a measure is applied that is comparable to the Dutch anti-hybrid rules (Articles 12aa or 12ab), or if the corresponding income is otherwise effectively included in a profit tax base.

Answer “no” if no such inclusion or equivalent adjustment takes place, meaning that the hybrid mismatch remains uncorrected in the relevant foreign jurisdiction(s).');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a4261724-4c1d-4790-91bc-7f3cbfc46522', '33', 'Does the Dutch permanent establishment recognise a deemed payment to the foreign head office or to another permanent establishment of the foreign taxpayer?', 'Unknown', '35', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-28 20:19:10.147994+00', 'Deemed payment from Dutch PE to non-EU head office', false, 'This question assesses whether, from a Dutch tax perspective, a deemed or notional payment is recognised between the Dutch permanent establishment and the foreign head office or another permanent establishment of the same foreign taxpayer.

Deemed payments arise where, for profit allocation purposes, internal dealings between a head office and its permanent establishments (or between two permanent establishments) are taken into account, even though no legal payment is made. Examples may include notional interest, royalties or service charges that are recognised solely for tax allocation purposes.

Answer “yes” if, under Dutch tax law and applicable tax treaties, the Dutch permanent establishment recognises such deemed payments when determining its taxable profit, meaning that these internal dealings are taken into account for Dutch corporate income tax purposes.

Answer “no” if the Dutch permanent establishment does not recognise such deemed payments and determines its taxable profit without taking internal dealings with the head office or other permanent establishments into account.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a5d3890b-f281-43e3-ace7-afe1c6d41e51', '14', 'Is the permanent establishment of the recipient recognized as such by the country where it is located?', 'Yes', '15', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-27 20:34:26.041971+00', 'PE recognition', false, 'This question determines whether there is a mismatch in the recognition of a permanent establishment between the country of the recipient and the country where the permanent establishment is purported to be located.

Answer “yes” if the permanent establishment is recognised as such under the tax law of the country where it is located, meaning that the profits attributable to that permanent establishment are, in principle, included in a tax base for a profit tax in that country.

Answer “no” if the country where the activities are carried out does not recognise the permanent establishment, for example because it considers that no permanent establishment exists under its domestic law or an applicable tax treaty.

This question is relevant because a difference in the recognition of a permanent establishment may result in income being exempt or disregarded in one country while not being taxed in the other, potentially giving rise to a hybrid mismatch within the scope of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a85dc943-708b-4acc-bc75-3d747720792d', '9', 'Are there any payments or remunerations made by the Dutch domestic taxpayer to an associated enterprise that are, either directly or indirectly, passed on to one or more other associated enterprises?', 'Unknown', '12', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-27 20:21:04.259393+00', NULL, false, 'This question determines whether a payment made by the Dutch domestic taxpayer forms part of a chain of transactions within the group, rather than ending with the direct recipient.

It is relevant because the Dutch anti-hybrid rules (ATAD 2) do not only apply to direct payments, but also to situations where a payment is directly or indirectly passed on to one or more other associated enterprises, for example through back-to-back arrangements, in-and-on-lending structures or other forms of onward funding.

Answer “yes” if the payment to the direct recipient is, in whole or in part, forwarded to another associated enterprise, or otherwise economically or contractually used to fund payments or deductions elsewhere in the group.

Answer “no” if the payment economically ends with the direct recipient and is not passed on, directly or indirectly, to another associated enterprise.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('a92dbdbb-88fc-4b4f-aa71-f5d5bee34cbb', '30', 'Has the Dutch domestic taxpayer transferred a financial instrument to a party in another country, and is the Dutch taxpayer considered the owner of the returns under Dutch tax law, while the other party is considered the owner of the same returns under the tax law of the other country?', 'Yes', 'end', '1.00', 'Hybrid transfer', 'An agreement to transfer a financial instrument where the underlying return of the transferred financial instrument is treated, for tax purposes, by the involved States as derived simultaneously by more than one of the parties to that agreement.', '2025-08-03 16:49:21.766755+00', '2025-12-29 11:46:26.969938+00', 'Hybrid transfer', true, 'This question determines whether the Dutch domestic taxpayer is involved in a hybrid transfer of a financial instrument, where different jurisdictions attribute the same return on that instrument to different parties.

A hybrid transfer arises where a financial instrument (such as shares, bonds or similar instruments) is transferred to a party in another country, but the tax laws of the involved jurisdictions do not agree on who is entitled to the economic return (for example interest or dividends). As a result, both jurisdictions may treat a different party as the owner of the same return for tax purposes.

Answer “yes” if:

- the Dutch domestic taxpayer has transferred a financial instrument to a party in another country, and
- under Dutch tax law, the Dutch taxpayer is still regarded as the owner of the returns on that instrument, while
- under the tax law of the other country, the counterparty is regarded as the owner of those same returns.

In such a case, the same return may be taken into account by more than one taxpayer or may give rise to a deduction without corresponding inclusion, which can result in a hybrid mismatch within the scope of the Dutch anti-hybrid rules.

Answer “no” if:
- both jurisdictions attribute the returns on the financial instrument to the same party, or
- the transfer does not affect the tax ownership of the returns in a way that leads to a qualification mismatch.
');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('ac0282f2-3ca8-42a1-83e5-6af78153119f', '1', 'Is the taxpayer subject to Dutch corporate income tax as a Dutch domestic taxpayer?', 'Yes', '3', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-28 21:06:28.556031+00', 'Resident taxpayer', true, 'This question determines whether the taxpayer falls within the scope of Dutch corporate income tax and therefore whether the Dutch anti-hybrid rules (ATAD 2) may apply.

Answer “yes” if the taxpayer qualifies as a Dutch domestic corporate income taxpayer under Article 2 of the Dutch Corporate Income Tax Act. This includes, in particular:

- entities that are tax resident in the Netherlands, meaning that their place of effective management is located in the Netherlands, based on the facts and circumstances, or

- entities that are incorporated under Dutch law and subject to Dutch corporate income tax, such as a private limited company (BV), public limited company (NV), or cooperative, or

- transparent partnerships or similar entities that qualify as an inverse hybrid entity and are therefore treated as a Dutch corporate income taxpayer under specific anti-hybrid provisions.

Answer “no” if the taxpayer does not fall within any of these categories and is not treated as a Dutch corporate income taxpayer under Dutch tax law.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('b2c3d4e5-2222-4222-8222-222222222221', '4c', 'Does the Dutch taxpayer have deductible costs, expenses or losses in the relevant tax year that are also deducted in the jurisdiction of the shareholder or participant that is considered an associated enterprise?', 'Yes', '4d', '1.00', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:05:43.668701+00', 'Double deduction with shareholder', true, 'This question is intended to identify situations in which the Dutch taxpayer claims a tax deduction for costs, expenses or losses, while the same amounts are also deducted in the jurisdiction of the shareholder or participant. Such situations may give rise to a double deduction within the meaning of the ATAD2 hybrid mismatch rules.

The term costs, expenses or losses should be interpreted broadly. It includes, among others:
- operating expenses incurred by the Dutch taxpayer
- interest expenses and other financing costs
- depreciation or amortisation
- losses arising from business activities
- other deductible expenses recognised under Dutch corporate income tax law
');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('b2c3d4e5-2222-4222-8222-222222222222', '4c', 'Does the Dutch taxpayer have deductible costs, expenses or losses in the relevant tax year that are also deducted in the jurisdiction of the shareholder or participant that is considered an associated enterprise?', 'No', '5', '0.00', 'associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-12-29 20:31:28.755394+00', '2025-12-30 10:05:28.449871+00', 'Double deduction with shareholder', false, 'This question is intended to identify situations in which the Dutch taxpayer claims a tax deduction for costs, expenses or losses, while the same amounts are also deducted in the jurisdiction of the shareholder or participant. Such situations may give rise to a double deduction within the meaning of the ATAD2 hybrid mismatch rules.

The term costs, expenses or losses should be interpreted broadly. It includes, among others:
- operating expenses incurred by the Dutch taxpayer
- interest expenses and other financing costs
- depreciation or amortisation
- losses arising from business activities
- other deductible expenses recognised under Dutch corporate income tax law
');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('b2c3d4e5-2222-4222-8222-222222222223', '4c', 'Does the Dutch taxpayer have deductible costs, expenses or losses in the relevant tax year that are also deducted in the jurisdiction of the shareholder or participant that is considered an associated enterprise?', 'Unknown', '5', '0.10', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:05:28.201561+00', 'Double deduction with shareholder', false, 'This question is intended to identify situations in which the Dutch taxpayer claims a tax deduction for costs, expenses or losses, while the same amounts are also deducted in the jurisdiction of the shareholder or participant. Such situations may give rise to a double deduction within the meaning of the ATAD2 hybrid mismatch rules.

The term costs, expenses or losses should be interpreted broadly. It includes, among others:
- operating expenses incurred by the Dutch taxpayer
- interest expenses and other financing costs
- depreciation or amortisation
- losses arising from business activities
- other deductible expenses recognised under Dutch corporate income tax law
');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('b7a907c3-05e5-442f-a2dd-e1149b7c0553', '13', 'Are any of the payments or remunerations (partially) attributable to the permanent establishment of the recipient?', 'Yes', '14', '1.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-08-26 17:30:49.962771+00', 'Attribution to PE', true, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('bb892508-419c-4f73-8266-7f40358e4d3d', '5', 'Does the Dutch domestic taxpayer make payments or provide remunerations to an associated enterprise (referred to as ''recipient'' in the following questions), which are in principle deductible for Dutch tax purposes?', 'No', '15', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-27 20:15:40.655509+00', 'Associated payments', false, 'The concept of a payment or remuneration is interpreted broadly and goes beyond amounts that are actually paid in cash.

It includes both payments that are factually made, such as interest, royalties or payments under financial instruments, and payments or remunerations that are deemed to be made for tax purposes. This also covers amounts that arise as a result of tax adjustments, including transfer pricing corrections or comparable foreign tax rules, even if no actual payment has taken place.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('be9e719e-d6e9-423f-a299-2658e23541d3', '29', 'Is the Dutch domestic taxpayer also considered a tax resident in another country?', 'Unknown', '30', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-28 15:03:25.163197+00', 'Dual residency', false, 'This question determines whether the Dutch domestic taxpayer is regarded as tax resident in more than one country at the same time.

Answer “yes” if, based on the domestic tax law of another country, the taxpayer is also considered tax resident there, for example because that country applies residence criteria such as place of effective management, incorporation, or a similar connecting factor. This may occur even if the taxpayer is clearly a Dutch tax resident under Dutch law.

Answer “no” if the taxpayer is regarded as tax resident only in the Netherlands under the relevant domestic tax laws.

This question is relevant because dual tax residence may give rise to a hybrid mismatch within the scope of the Dutch anti-hybrid rules.

If dual residence exists, further analysis is required to determine whether the residence conflict is resolved under a tax treaty (for example through a tie-breaker rule) and whether the Dutch anti-hybrid rules on double residence mismatches may apply.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c0574ad3-798d-4cc3-92bf-4d4cec88ce8b', '33', 'Does the Dutch permanent establishment recognise a deemed payment to the foreign head office or to another permanent establishment of the foreign taxpayer?', 'No', '35', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-28 20:19:08.391483+00', 'Deemed payment from Dutch PE to non-EU head office', false, 'This question assesses whether, from a Dutch tax perspective, a deemed or notional payment is recognised between the Dutch permanent establishment and the foreign head office or another permanent establishment of the same foreign taxpayer.

Deemed payments arise where, for profit allocation purposes, internal dealings between a head office and its permanent establishments (or between two permanent establishments) are taken into account, even though no legal payment is made. Examples may include notional interest, royalties or service charges that are recognised solely for tax allocation purposes.

Answer “yes” if, under Dutch tax law and applicable tax treaties, the Dutch permanent establishment recognises such deemed payments when determining its taxable profit, meaning that these internal dealings are taken into account for Dutch corporate income tax purposes.

Answer “no” if the Dutch permanent establishment does not recognise such deemed payments and determines its taxable profit without taking internal dealings with the head office or other permanent establishments into account.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c263b3f1-9469-48e4-afc3-0c21f344a7f5', '27', 'Does the hybrid entity receive a payment or remuneration from an associated enterprise that is in principle deductible at the level of that associated enterprise, while that payment is not included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as tax transparent?
', 'Yes', '28', '1.00', 'Hybrid entity', 'An entity that is regarded as a taxable entity under the laws of one State, and whose income or expenditure is treated as income or expenditure of one or more other entities or individuals under the laws of another jurisdiction.', '2025-08-03 16:49:21.766755+00', '2025-12-28 15:04:33.977975+00', 'Deductible payment to hybrid entity', true, 'This question determines whether the payment received by the hybrid entity is not included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as tax transparent, which may give rise to a hybrid mismatch from the perspective of the Dutch participant.

Answer “yes” if, because the hybrid entity is treated as tax transparent in the relevant jurisdiction, the payment is not recognised as taxable income at the level of the hybrid entity or its participant(s). In that case, the payment is deducted by the payer but not taxed anywhere, which may constitute a deduction without inclusion within the scope of the Dutch anti-hybrid rules.

Answer “no” if the payment is included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as transparent, for example because the income is taxed at the level of one or more participants.

A “yes” answer indicates a potential ATAD2 risk and requires further assessment to determine whether the Dutch secondary rule applies and whether the income must be included in the Dutch tax base.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c2c3b60d-0ebe-418c-acc5-00b5b90fed3c', '2', 'Is the taxpayer a legal entity that is not a resident of the Netherlands, but is subject to Dutch corporate income tax as a non-resident taxpayer because it has a permanent establishment in the Netherlands?', 'No', 'end', '-1.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-27 19:14:59.087473+00', 'Non-resident taxpayer', false, 'This question determines whether the taxpayer falls within the scope of Dutch corporate income tax as a non-resident taxpayer and therefore whether the Dutch anti-hybrid rules (ATAD2) may apply.

Answer “yes” if the taxpayer qualifies as a Dutch non-resident corporate income taxpayer under Article 3 of the Dutch Corporate Income Tax Act. This includes, in particular:

entities that are not tax resident in the Netherlands, but that derive Dutch-source income through a permanent establishment in the Netherlands within the meaning of Dutch tax law or an applicable tax treaty, and are therefore subject to Dutch corporate income tax with respect to the profits attributable to that permanent establishment.

Answer “no” if the taxpayer does not have a permanent establishment in the Netherlands and is therefore not treated as a Dutch non-resident corporate income taxpayer under Dutch tax law.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c3d4e5f6-3333-4333-8333-333333333331', '4d', 'Is there corresponding income that is included in the taxable base of both the Dutch taxpayer and the shareholder or participant, which can be set off against the deductible payment, cost, expense or loss?', 'Yes', '5', '-1.00', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:12:40.74666+00', 'Dual inclusion income offset', true, 'For this purpose, it is relevant whether the same income component is included, by or under the tax laws of both jurisdictions involved, in a tax on profits or income:
- at the level of the Dutch taxpayer under Dutch tax law, and
- at the level of the shareholder or participant under the tax law of that jurisdiction.

The assessment focuses on legal inclusion in principle in both jurisdictions. The effective tax outcome is not decisive. The existence of tax losses, loss carry-forward, or other mechanisms affecting the final tax payable does not prevent income from qualifying as dual inclusion income.

There is no requirement that the income is economically or transactionally linked to the deductible payment, cost, expense or loss. It is sufficient that the income is included in the taxable base of both jurisdictions as a result of differences in tax classification or allocation.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c3d4e5f6-3333-4333-8333-333333333332', '4d', 'Is there corresponding income that is included in the taxable base of both the Dutch taxpayer and the shareholder or participant, which can be set off against the deductible payment, cost, expense or loss?', 'No', '5', '0.00', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:12:45.975128+00', 'Dual inclusion income offset', false, 'For this purpose, it is relevant whether the same income component is included, by or under the tax laws of both jurisdictions involved, in a tax on profits or income:
- at the level of the Dutch taxpayer under Dutch tax law, and
- at the level of the shareholder or participant under the tax law of that jurisdiction.

The assessment focuses on legal inclusion in principle in both jurisdictions. The effective tax outcome is not decisive. The existence of tax losses, loss carry-forward, or other mechanisms affecting the final tax payable does not prevent income from qualifying as dual inclusion income.

There is no requirement that the income is economically or transactionally linked to the deductible payment, cost, expense or loss. It is sufficient that the income is included in the taxable base of both jurisdictions as a result of differences in tax classification or allocation.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c3d4e5f6-3333-4333-8333-333333333333', '4d', 'Is there corresponding income that is included in the taxable base of both the Dutch taxpayer and the shareholder or participant, which can be set off against the deductible payment, cost, expense or loss?', 'Unknown', '5', '0.10', NULL, NULL, '2025-12-29 20:31:28.755394+00', '2025-12-30 10:12:47.283416+00', 'Dual inclusion income offset', false, 'For this purpose, it is relevant whether the same income component is included, by or under the tax laws of both jurisdictions involved, in a tax on profits or income:
- at the level of the Dutch taxpayer under Dutch tax law, and
- at the level of the shareholder or participant under the tax law of that jurisdiction.

The assessment focuses on legal inclusion in principle in both jurisdictions. The effective tax outcome is not decisive. The existence of tax losses, loss carry-forward, or other mechanisms affecting the final tax payable does not prevent income from qualifying as dual inclusion income.

There is no requirement that the income is economically or transactionally linked to the deductible payment, cost, expense or loss. It is sufficient that the income is included in the taxable base of both jurisdictions as a result of differences in tax classification or allocation.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c4d1c5af-2da2-4b3e-8668-132940aba0ad', '29', 'Is the Dutch domestic taxpayer also considered a tax resident in another country?', 'No', '30', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-28 15:03:22.68538+00', 'Dual residency', false, 'This question determines whether the Dutch domestic taxpayer is regarded as tax resident in more than one country at the same time.

Answer “yes” if, based on the domestic tax law of another country, the taxpayer is also considered tax resident there, for example because that country applies residence criteria such as place of effective management, incorporation, or a similar connecting factor. This may occur even if the taxpayer is clearly a Dutch tax resident under Dutch law.

Answer “no” if the taxpayer is regarded as tax resident only in the Netherlands under the relevant domestic tax laws.

This question is relevant because dual tax residence may give rise to a hybrid mismatch within the scope of the Dutch anti-hybrid rules.

If dual residence exists, further analysis is required to determine whether the residence conflict is resolved under a tax treaty (for example through a tie-breaker rule) and whether the Dutch anti-hybrid rules on double residence mismatches may apply.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c919908e-af46-4ef1-8517-3e762ecb9f70', '1', 'Is the taxpayer subject to Dutch corporate income tax as a Dutch domestic taxpayer?
', 'Unknown', '2', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-28 21:06:30.807781+00', 'Resident taxpayer', false, 'This question determines whether the taxpayer falls within the scope of Dutch corporate income tax and therefore whether the Dutch anti-hybrid rules (ATAD 2) may apply.

Answer “yes” if the taxpayer qualifies as a Dutch domestic corporate income taxpayer under Article 2 of the Dutch Corporate Income Tax Act. This includes, in particular:

- entities that are tax resident in the Netherlands, meaning that their place of effective management is located in the Netherlands, based on the facts and circumstances, or

- entities that are incorporated under Dutch law and subject to Dutch corporate income tax, such as a private limited company (BV), public limited company (NV), or cooperative, or

- transparent partnerships or similar entities that qualify as an inverse hybrid entity and are therefore treated as a Dutch corporate income taxpayer under specific anti-hybrid provisions.

Answer “no” if the taxpayer does not fall within any of these categories and is not treated as a Dutch corporate income taxpayer under Dutch tax law.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('c9e7e276-da0a-4b67-987b-11d065a4f09e', '10', 'Does the payment, either directly or through onward payment, ultimately reach one or more associated enterprises that are resident outside the EU (third countries)?', 'Unknown', '12', '0.10', 'Associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-08-11 17:48:52.737035+00', '2025-12-27 20:30:48.715406+00', 'Non-EU associated enterprise', false, 'This question determines whether the payment may be connected to a hybrid mismatch between third countries, which is a key condition for the possible application of the imported hybrid mismatch rules.

Answer “yes” if the payment is made, directly or indirectly, to one or more associated enterprises resident outside the European Union.

Answer “no” if all associated enterprises that ultimately receive the payment are resident within the European Union.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('cc1e2259-d084-4d81-a905-f4ed89900cdf', '13', 'Are any of the payments or remunerations (partially) attributable to the permanent establishment of the recipient?', 'Unknown', '15', '0.10', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:25.081651+00', 'Attribution to PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('ce5802d7-e400-4d46-9db5-5fb3fefe8041', '23c', 'Is the income allocated to the foreign permanent establishment included in a taxable base for a profit tax in the country where that permanent establishment is located?', 'No', '24', '1.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-12-28 12:40:02.90026+00', '2025-12-28 12:47:25.896501+00', 'Inclusion of PE income in taxable base', true, 'This question determines whether the income that is allocated to the foreign permanent establishment is effectively taxed in the country where that permanent establishment is located.

Answer “yes” if the allocated income is included in a taxable base for a profit tax in the permanent establishment state, regardless of the applicable tax rate or the use of loss offsets.

Answer “no” if the allocated income is not included in a profit tax base in that country, for example because the permanent establishment is not recognised, the income is exempt, or the allocation is not followed for tax purposes.

This assessment must be made from the perspective of the permanent establishment state. If the income is not taxed in that jurisdiction, while it is also not taxed in the Netherlands due to allocation to the foreign permanent establishment, this may result in income not being taxed in any state and may trigger the application of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('cff72740-c985-441a-b784-f5bad4a7c5a6', '9', 'Are there any payments or remunerations made by the Dutch domestic taxpayer to an associated enterprise that are, either directly or indirectly, passed on to one or more other associated enterprises?', 'Yes', '10', '0.00', 'associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-08-03 16:49:21.766755+00', '2025-12-27 20:21:05.911857+00', 'Pass-through payment', true, 'This question determines whether a payment made by the Dutch domestic taxpayer forms part of a chain of transactions within the group, rather than ending with the direct recipient.

It is relevant because the Dutch anti-hybrid rules (ATAD 2) do not only apply to direct payments, but also to situations where a payment is directly or indirectly passed on to one or more other associated enterprises, for example through back-to-back arrangements, in-and-on-lending structures or other forms of onward funding.

Answer “yes” if the payment to the direct recipient is, in whole or in part, forwarded to another associated enterprise, or otherwise economically or contractually used to fund payments or deductions elsewhere in the group.

Answer “no” if the payment economically ends with the direct recipient and is not passed on, directly or indirectly, to another associated enterprise.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('d31f789f-2395-42e6-aefc-0c5a41168c98', '21b', 'Is this deemed payment disregarded for tax purposes in the country where the permanent establishment is located?', 'No', '22b', '0.00', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-08-03 16:49:21.766755+00', '2025-12-28 21:10:32.624886+00', 'Disregarded deemed payment at PE level', false, 'This question determines whether a deemed or notional payment between the head office and the permanent establishment is ignored (disregarded) for tax purposes in the country where the permanent establishment is located.

A deemed payment is regarded as disregarded if, under the tax law or treaty practice of the permanent establishment state, internal dealings between a head office and its permanent establishment are not recognised as taxable transactions. This is typically the case where the permanent establishment state:

- does not recognise internal interest, royalties or service charges between a head office and its permanent establishment,

- determines the taxable profit of the permanent establishment solely on the basis of an overall profit allocation, without recognising internal transactions, or

- treats the head office and the permanent establishment as a single taxpayer for purposes of profit taxation.

Answer “yes” if the deemed payment is ignored for tax purposes in the permanent establishment state and therefore does not give rise to taxable income at the level of the permanent establishment.

Answer “no” if the permanent establishment state does recognise such deemed payments and includes them in the determination of the taxable profit of the permanent establishment.

This assessment must be made from the perspective of the permanent establishment state');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('d35d41c4-d0ce-484f-a727-41ae7bc40db5', '6', 'Is at least one of these recipients a hybrid entity?', 'Unknown', '8', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-27 20:01:42.567901+00', NULL, false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('d3b21532-97f9-4633-bd2d-2e01e39da2e3', '29', 'Is the Dutch domestic taxpayer also considered a tax resident in another country?', 'Yes', '30', '1.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-28 15:03:26.869465+00', 'Dual residency', true, 'This question determines whether the Dutch domestic taxpayer is regarded as tax resident in more than one country at the same time.

Answer “yes” if, based on the domestic tax law of another country, the taxpayer is also considered tax resident there, for example because that country applies residence criteria such as place of effective management, incorporation, or a similar connecting factor. This may occur even if the taxpayer is clearly a Dutch tax resident under Dutch law.

Answer “no” if the taxpayer is regarded as tax resident only in the Netherlands under the relevant domestic tax laws.

This question is relevant because dual tax residence may give rise to a hybrid mismatch within the scope of the Dutch anti-hybrid rules.

If dual residence exists, further analysis is required to determine whether the residence conflict is resolved under a tax treaty (for example through a tie-breaker rule) and whether the Dutch anti-hybrid rules on double residence mismatches may apply.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('d63527dd-eb36-4e3b-99c1-ff2ffb26c95f', '33', 'Does the Dutch permanent establishment recognize a deemed payment to the foreign head office or to another permanent establishment of the foreign taxpayer?', 'Yes', '34', '0.00', 'Example 5', 'The balance sheet of a foreign head office includes a mobile installation. This installation is temporarily made available to a PE in the Netherlands. The remuneration (i.e. the deemed payment) involved, is in principle deductible from the PE profit in the Netherlands. Due to the fact that the remuneration (the deemed payment) is not included in the profit of the head office based on local tax legislation, a mismatch occurs. In this case, the remuneration (deemed payment) is not deductible from the PE profit in the Netherlands.', '2025-08-03 16:49:21.766755+00', '2025-12-28 20:19:11.222755+00', 'Deemed payment from Dutch PE to non-EU head office', true, 'This question assesses whether, from a Dutch tax perspective, a deemed or notional payment is recognised between the Dutch permanent establishment and the foreign head office or another permanent establishment of the same foreign taxpayer.

Deemed payments arise where, for profit allocation purposes, internal dealings between a head office and its permanent establishments (or between two permanent establishments) are taken into account, even though no legal payment is made. Examples may include notional interest, royalties or service charges that are recognised solely for tax allocation purposes.

Answer “yes” if, under Dutch tax law and applicable tax treaties, the Dutch permanent establishment recognises such deemed payments when determining its taxable profit, meaning that these internal dealings are taken into account for Dutch corporate income tax purposes.

Answer “no” if the Dutch permanent establishment does not recognise such deemed payments and determines its taxable profit without taking internal dealings with the head office or other permanent establishments into account.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('d7892075-91bf-4a8b-8140-14d3e6585c7a', '23b', 'Is the received amount (partially) allocated to a foreign permanent establishment of the Dutch domestic taxpayer, and therefore not fully included in the Dutch tax base?', 'No', '26', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-28 12:34:42.657552+00', 'Allocation of inbound payment to foreign PE', false, 'This question determines whether the income received by the Dutch domestic taxpayer is wholly or partly attributed to a foreign permanent establishment, as a result of which that income is not fully included in the Dutch tax base.

Answer “yes” if, under Dutch tax law and applicable tax treaties, the received amount is (partly) allocated to a foreign permanent establishment of the taxpayer and therefore falls outside the Dutch taxable profit, for example because the foreign permanent establishment’s profits are exempt under the object exemption.

Answer “no” if the received amount is fully included in the Dutch tax base and no part of the income is attributed to a foreign permanent establishment.

This question is relevant because allocating income to a foreign permanent establishment may result in the income not being taxed in the Netherlands, which requires further assessment under the Dutch anti-hybrid rules to determine whether the income is taxed in the state of the permanent establishment or gives rise to a hybrid mismatch.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('d92f2774-5823-4da4-8014-577f97d6e21a', '4', 'Are any of the shareholder(s) or participant(s) an associated enterprise of the Dutch entity that, based on their own local tax law, treat the Dutch entity as a separate taxable entity (non-transparent), while the Netherlands treats it as tax transparent?', 'No', '4b', '0.00', 'associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-08-03 16:49:21.766755+00', '2025-12-29 20:32:18.14729+00', 'Reverse-hybrid classification conflict', false, 'For the purpose of this question, the Dutch entity (typically a partnership such as a CV, VOF or maatschap) is treated as tax transparent in the Netherlands, meaning its income, expenses and losses are attributed directly to its participants. A reverse-hybrid classification conflict arises where an associated shareholder or participant, under its own local tax law, instead treats that same Dutch entity as a separate taxable entity (non-transparent), so that its income is not currently taxed at either level. Article 2 paragraph 11 CIT Act then treats the Dutch entity itself as a Dutch taxpayer.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('db071ab7-4eeb-4a81-94cc-2873413d60b9', '13', 'Are any of the payments or remunerations (partially) attributable to the permanent establishment of the recipient?', 'No', '15', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-08-12 14:23:39.227654+00', 'Attribution to PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('dc634cf9-ce11-45cf-a09c-d2542f746d7a', '15', 'Does the Dutch domestic taxpayer have one or more foreign permanent establishments?', 'No', '26', '0.00', 'Permanent establishment', 'A fixed place of business, resident in another State than the State in which the head office is a resident, through which the activities of an enterprise are wholly or in part carried out, with the understanding that a building site or construction or installation project constitutes a permanent establishment only if it lasts more than twelve months. If the Netherlands has concluded a tax treaty with the other State, the definition included in the treaty is applicable.', '2025-08-03 16:49:21.766755+00', '2025-12-28 10:46:39.533197+00', 'Foreign PE of taxpayer', false, 'This question determines whether the Dutch domestic taxpayer has a foreign permanent establishment for Dutch tax purposes.

Answer “yes” if, based on Dutch tax law and an applicable tax treaty, the taxpayer carries on business abroad through a permanent establishment. The assessment must be made from a Dutch tax perspective, meaning that it is not decisive how the foreign jurisdiction itself qualifies the activities or presence.

Answer “no” if, when assessed under Dutch tax law and relevant tax treaties, no foreign permanent establishment exists, even if the foreign jurisdiction takes a different view.

This question is relevant because differences in the recognition or allocation of income to a permanent establishment may give rise to hybrid mismatches within the scope of the Dutch anti-hybrid rules.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('de9a24eb-d45e-4211-bbe8-bb8051ec24d2', '10', 'Does the payment, either directly or through onward payment, ultimately reach one or more associated enterprises that are resident outside the EU (third countries)?', 'No', '12', '0.00', 'Associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-08-03 16:49:21.766755+00', '2025-12-27 20:30:41.203183+00', 'Non-EU associated enterprise', false, 'This question determines whether the payment may be connected to a hybrid mismatch between third countries, which is a key condition for the possible application of the imported hybrid mismatch rules.

Answer “yes” if the payment is made, directly or indirectly, to one or more associated enterprises resident outside the European Union.

Answer “no” if all associated enterprises that ultimately receive the payment are resident within the European Union.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('e29cbc26-2cf2-4d8c-8db9-3dc4fb945677', '27', 'Does the hybrid entity receive a payment or remuneration from an associated enterprise that is in principle deductible at the level of that associated enterprise, while that payment is not included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as tax transparent?
', 'Unknown', '28', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-12-28 15:04:50.223931+00', 'Deductible payment to hybrid entity', false, 'This question determines whether the payment received by the hybrid entity is not included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as tax transparent, which may give rise to a hybrid mismatch from the perspective of the Dutch participant.

Answer “yes” if, because the hybrid entity is treated as tax transparent in the relevant jurisdiction, the payment is not recognised as taxable income at the level of the hybrid entity or its participant(s). In that case, the payment is deducted by the payer but not taxed anywhere, which may constitute a deduction without inclusion within the scope of the Dutch anti-hybrid rules.

Answer “no” if the payment is included in a taxable base for a profit tax in the jurisdiction that treats the hybrid entity as transparent, for example because the income is taxed at the level of one or more participants.

A “yes” answer indicates a potential ATAD2 risk and requires further assessment to determine whether the Dutch secondary rule applies and whether the income must be included in the Dutch tax base.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('e3e19a52-1852-4db1-9764-f073efe5b0b0', '22b', 'Does the Dutch domestic taxpayer receive payments or remunerations from an associated enterprise located outside the EU, which are in principle deductible for tax purposes in that non-EU country?', 'No', '26', '0.00', 'Associated enterprise', 'An associated enterprise exists where there is a material sphere of influence between parties. In principle, this is the case if the taxpayer holds, or is held by, an interest of at least 25 percent in another enterprise, whether through capital, voting rights or profit rights. 

Enterprises are also associated if they are sister companies held by a common shareholder, if interests are held jointly by parties acting together, or if the taxpayer forms part of the same group under Dutch or comparable foreign consolidation rules. Whether entities act together is determined based on the facts and circumstances, and transparency or non-transparency for tax purposes is not decisive.
Answer “yes” if any such deductible payments or remunerations are made to an associated enterprise. 

Answer “no” only if no such payments or remunerations exist.', '2025-08-03 16:49:21.766755+00', '2025-12-28 12:33:09.426642+00', 'Inbound payment from non-EU associated enterprise', false, 'This question determines whether the Dutch domestic taxpayer receives payments or remunerations from an associated enterprise that is located outside the European Union, where those payments are, in principle, deductible for tax purposes in the payer’s jurisdiction.

Answer “yes” if an associated enterprise resident in a non-EU country makes payments or provides remunerations to the Dutch taxpayer that reduce its taxable profit under a tax on profits in that country, regardless of whether the deduction is actually used in a specific year.

Answer “no” if the payments are not deductible in the payer’s jurisdiction, or if the payer is resident within the European Union.

This question is relevant because, where a non-EU payer deducts a payment and no comparable anti-hybrid rules apply in that jurisdiction, the Netherlands may be required to apply the secondary ATAD2 rule if the corresponding income is not effectively included in a taxable base elsewhere.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('e704d696-5a96-4eb7-b6b6-036266319530', '20b', 'Is there a deemed payment, which is in principle deductible in the Netherlands, to one or more foreign permanent establishments?', 'Unknown', '22b', '0.10', 'Deemed payment', 'A payment or remuneration that is treated for tax purposes as a transaction between different parts of a single legal entity, such as a head office and a permanent establishment, even if no actual cash flow has occurred. It is an internal allocation relevant for tax calculation.', '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:36.674933+00', 'Deemed payment to PE', false, NULL);
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('e7e6f5ab-4af2-4477-a456-41be2a67b06e', '28', 'Has the Dutch domestic taxpayer entered into a so-called structured arrangement with a third party that has led to a double deduction or a deduction without inclusion?', 'Yes', '29', '1.00', 'Structured arrangement', 'A structured arrangement exists where a transaction or set of transactions is designed, priced or documented in such a way that a hybrid mismatch outcome (a double deduction or a deduction without inclusion) is an integral part of the arrangement, even if the parties are not associated. In such cases, the tax benefit resulting from the hybrid mismatch is typically reflected in the terms of the arrangement, for example through pricing, profit sharing or risk allocation.', '2025-08-03 16:49:21.766755+00', '2025-12-29 11:45:24.080586+00', 'Structured arrangement', true, 'This question determines whether a potential hybrid mismatch arises from a structured arrangement involving a third party, rather than from a direct relationship between associated enterprises.

Answer “yes” if the Dutch domestic taxpayer has entered into an arrangement with a third party where:

- a double deduction or a deduction without inclusion arises, and
- that outcome can reasonably be regarded as built into or anticipated by the arrangement, regardless of whether the taxpayer intended to obtain a tax advantage.

Answer “no” if the transaction is a standard commercial arrangement with a third party and any hybrid mismatch outcome is incidental or unknown to the parties, and not reflected in the terms or pricing of the arrangement.

This question is relevant because the Dutch anti-hybrid rules also apply to hybrid mismatches arising from structured arrangements with non-associated parties. A “yes” answer therefore brings the transaction within the scope of ATAD2, even in the absence of a group relationship.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('e7f88bd4-cdc1-4acf-a5fb-59274aafe81c', '9', 'Are there any payments or remunerations made by the Dutch domestic taxpayer to an associated enterprise that are, either directly or indirectly, passed on to one or more other associated enterprises?', 'No', '12', '0.00', NULL, NULL, '2025-08-03 16:49:21.766755+00', '2025-12-27 20:21:11.879674+00', 'Pass-through payment', false, 'This question determines whether a payment made by the Dutch domestic taxpayer forms part of a chain of transactions within the group, rather than ending with the direct recipient.

It is relevant because the Dutch anti-hybrid rules (ATAD 2) do not only apply to direct payments, but also to situations where a payment is directly or indirectly passed on to one or more other associated enterprises, for example through back-to-back arrangements, in-and-on-lending structures or other forms of onward funding.

Answer “yes” if the payment to the direct recipient is, in whole or in part, forwarded to another associated enterprise, or otherwise economically or contractually used to fund payments or deductions elsewhere in the group.

Answer “no” if the payment economically ends with the direct recipient and is not passed on, directly or indirectly, to another associated enterprise.');
INSERT INTO public.atad2_questions (id, question_id, question, answer_option, next_question_id, risk_points, difficult_term, term_explanation, created_at, updated_at, question_title, requires_explanation, question_explanation) VALUES ('e93e92bd-783f-4f89-aeff-c31e2cf8cccf', '24', 'Are there deemed payments made by a permanent establishment located outside the EU, which are in principle deductible in that country, to the Dutch domestic taxpayer (head office in the Netherlands)?', 'Unknown', '26', '0.10', NULL, NULL, '2025-08-11 17:48:52.737035+00', '2025-08-17 18:39:43.865012+00', 'Deemed payment from non-EU PE to Dutch head office', false, NULL);

