INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('037e602b-dc71-46cd-9afd-1468ca67947f', '1', 'Yes', 'Great, a Dutch tax resident! Feel free to share any additional context about the entity that might be relevant for our analysis.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('047deb4a-f4aa-4d4a-8c3b-6ff6fe43b92c', '4', 'Yes', 'This ''dual view'' is a classic ATAD2 trigger. Any additional background you can provide is more than welcome.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('04f2dba2-d6a7-43a5-b664-7eb0c1441537', '15', 'Yes', 'Foreign PEs in the mix - the structure is expanding! Any additional details you''d like to share are welcome.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('053426e3-156f-4685-ac21-91a72497627c', '26', 'Yes', 'Participation in an entity with a split personality. Any additional background you''d like to provide is welcome.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('07953000-c552-4732-b373-c71ce37139a7', '5', 'Yes', 'Intercompany payments - the bread and butter of international tax! Any additional details you''d like to provide are welcome.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('0bd40ec9-e671-43fd-b2a6-f1b90a8e2a6b', '25', 'No', 'So the foreign PE gets a deduction, but the Netherlands doesn''t pick up the income - a mismatch! Feel free to share any context.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('0c6f2126-4852-4c47-8a62-973531115989', '29', 'Yes', 'Two countries claiming the same taxpayer - a classic conflict! Any additional details you''d like to provide are welcome.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('14b30221-dd80-46b6-880e-98984f480691', '33', 'Yes', 'The Dutch PE recognises an internal transaction. Feel free to share any relevant background.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('1b2d5939-2582-4edf-9841-f356ee77777a', '13', 'Yes', 'The payment is (partly) allocated to the PE - interesting! Any additional details are welcome.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('248c7a5e-c7b8-49b4-a9ea-c5cf38f3456b', '22b', 'Yes', 'Non-EU money flowing into the Netherlands - interesting! Any additional background is welcome.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('258c9cb9-4050-434d-9587-539811687381', '13', 'Yes', 'So the PE is involved in this flow. Feel free to provide any background that might be relevant.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('2600ddab-1b1b-4758-b9de-ab214db6db62', '14', 'No', 'A ''phantom PE'' - it exists for one country but not for the other! Feel free to share any context about this recognition conflict.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('29c12d7f-536a-4f26-8db1-94672a771b9e', '19', 'Yes', 'So the same costs are being ''double-dipped''. Feel free to provide any background that might be relevant.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('2bd685a2-96b0-499e-9bde-9bbe15449547', '22b', 'Yes', 'Payments coming in from outside the EU - the secondary rules might come into play! Feel free to share any context about these inbound flows.', '2025-12-30 11:01:41.519581+00');
INSERT INTO public.atad2_context_questions (id, question_id, answer_trigger, context_question, created_at) VALUES ('2e1e1bbb-20bd-44df-82f3-4047b8875f12', '1', 'Yes', 'Perfect, that means we''re in the right place. Any background information you''d like to add is more than welcome.', '2025-12-30 11:01:41.519581+00');
